import{_ as l,o as i,c as t,ag as e}from"./chunks/framework.D_Vktuop.js";const b=JSON.parse('{"title":"nanobot 项目介绍","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md","lastUpdated":null}'),o={name:"guide/introduction.md"};function r(n,a,h,s,d,u){return i(),t("div",null,[...a[0]||(a[0]=[e('<h1 id="nanobot-项目介绍" tabindex="-1">nanobot 项目介绍 <a class="header-anchor" href="#nanobot-项目介绍" aria-label="Permalink to &quot;nanobot 项目介绍&quot;">​</a></h1><blockquote><p>超轻量级个人 AI 助手框架</p></blockquote><p>nanobot 是一个超轻量级的个人 AI 助手框架，灵感来源于 OpenClaw。</p><h2 id="核心特性" tabindex="-1">核心特性 <a class="header-anchor" href="#核心特性" aria-label="Permalink to &quot;核心特性&quot;">​</a></h2><h3 id="超轻量" tabindex="-1">超轻量 <a class="header-anchor" href="#超轻量" aria-label="Permalink to &quot;超轻量&quot;">​</a></h3><ul><li>核心代码仅约 4000 行（不含 channels/, cli/, providers/）</li><li>比 OpenClaw 小 99%</li><li>易于理解和修改</li></ul><h3 id="多平台支持" tabindex="-1">多平台支持 <a class="header-anchor" href="#多平台支持" aria-label="Permalink to &quot;多平台支持&quot;">​</a></h3><p>支持以下聊天平台：</p><ul><li>Telegram</li><li>Discord</li><li>WhatsApp</li><li>Feishu</li><li>QQ</li><li>Slack</li><li>Email</li><li>Matrix</li><li>DingTalk</li></ul><h3 id="高性能" tabindex="-1">高性能 <a class="header-anchor" href="#高性能" aria-label="Permalink to &quot;高性能&quot;">​</a></h3><ul><li>基于 asyncio 的异步架构</li><li>消息队列解耦各组件</li><li>支持并发处理多个会话</li></ul><h3 id="插件化架构" tabindex="-1">插件化架构 <a class="header-anchor" href="#插件化架构" aria-label="Permalink to &quot;插件化架构&quot;">​</a></h3><ul><li>可扩展的聊天通道系统</li><li>灵活的工具系统</li><li>多 LLM 提供商支持</li></ul><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><p>nanobot 特别适合以下场景：</p><ol><li><strong>个人 AI 助手</strong>: 在你常用的聊天平台上有自己的 AI 助手</li><li><strong>学习 AI 应用开发</strong>: 代码清晰，适合学习 LLM 应用架构</li><li><strong>快速原型开发</strong>: 轻量级设计，快速迭代</li><li><strong>自定义集成</strong>: 插件化架构，易于扩展</li></ol><h2 id="版本信息" tabindex="-1">版本信息 <a class="header-anchor" href="#版本信息" aria-label="Permalink to &quot;版本信息&quot;">​</a></h2><ul><li><strong>当前版本</strong>: v0.1.4.post4</li><li><strong>Python 要求</strong>: ≥ 3.11</li><li><strong>许可证</strong>: MIT</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li>了解<a href="./architecture.html">架构设计</a></li><li>查看<a href="./overview/tech-stack.html">技术栈</a></li><li>阅读<a href="./overview/directory-structure.html">目录结构</a></li></ul>',20)])])}const p=l(o,[["render",r]]);export{b as __pageData,p as default};
